class Solution:
    def recoverHeap(self, nums: list[int]) -> None:
        for i in range(1, len(nums)):
            j = len(nums) - i - 1
            while j >= 0:
                if nums[j] < nums[j + 1]:
                    nums[j], nums[j + 1] = nums[j + 1], nums[j]
                j -= 1
            for i in range(1, len(nums) // 2 + 1):
                self.heapify(nums, 0, i)

def heapify(self, nums: list[int], i: int, n: int) -> None:
    if 2 * i + 1 >= n:
        return
    max_idx = i
    left_idx = 2 * i + 1
    right_idx = 2 * i + 2
    if nums[left_idx] > nums[max_idx]:
        max_idx = left_idx
    if right_idx < n and nums[right_idx] > nums[max_idx]:
        max_idx = right_idx
    if max_idx != i:
        nums[i], nums[max_idx] = nums[max_idx], nums[i]
        self.heapify(nums, max_idx, n)



class Solution:
    def recoverHeap(self, nums: list[int]) -> None:
        heap = []
        for num in reversed(nums):
            heap.append(num)
            self.heapify(heap, 0, len(heap))
        nums[:] = list(reversed(heap))

def heapify(self, nums: list[int], i: int, n: int) -> None:
    if 2 * i + 1 >= n:
        return
    max_idx = i
